import requests


class KongAdminAPI:
    def __init__(self, admin_url: str, timeout: int = 10):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({"Content-Type": "application/json"})

    def _url(self, path: str) -> str:
        return f"{self.admin_url}/{path.lstrip('/')}"

    def _request(self, method: str, path: str, payload: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        response = self.session.request(
            method=method,
            url=self._url(path),
            json=payload,
            timeout=self.timeout,
        )
        if not response.ok:
            try:
                body = response.json()
            except Exception:
                body = response.text
            raise RuntimeError(f"{method} {path} failed: {response.status_code} {body}")
        if response.text.strip():
            try:
                return response.json()
            except Exception:
                return {"raw": response.text}
        return {}

    def get(self, path: str) -> Dict[str, Any]:
        return self._request("GET", path)

    def post(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("POST", path, payload)

    def put(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("PUT", path, payload)

    def patch(self, path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
        return self._request("PATCH", path, payload)


def ensure_service(client: KongAdminAPI, service: Dict[str, Any]) -> Dict[str, Any]:
    name = service["name"]
    payload = {k: v for k, v in service.items() if k != "routes"}
    return client.put(f"/services/{name}", payload)


def ensure_route(client: KongAdminAPI, service_name: str, route: Dict[str, Any]) -> Dict[str, Any]:
    route_name = route["name"]
    payload = dict(route)
    payload["service"] = {"name": service_name}
    return client.put(f"/routes/{route_name}", payload)


def ensure_upstream(client: KongAdminAPI, upstream: Dict[str, Any]) -> Dict[str, Any]:
    name = upstream["name"]
    payload = {k: v for k, v in upstream.items() if k != "targets"}
    return client.put(f"/upstreams/{name}", payload)


def ensure_target(client: KongAdminAPI, upstream_name: str, target: Dict[str, Any]) -> Dict[str, Any]:
    return client.post(f"/upstreams/{upstream_name}/targets", target)


def configure_kong(client: KongAdminAPI, config: Dict[str, Any]) -> Dict[str, Any]:
    results = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in config.get("upstreams", []):
        upstream_result = ensure_upstream(client, upstream)
        results["upstreams"].append(upstream_result)
        for target in upstream.get("targets", []):
            target_result = ensure_target(client, upstream["name"], target)
            results["targets"].append(target_result)

    for service in config.get("services", []):
        service_result = ensure_service(client, service)
        results["services"].append(service_result)
        for route in service.get("routes", []):
            route_result = ensure_route(client, service["name"], route)
            results["routes"].append(route_result)

    return results


