def wait_for_kong(client: KongAdminAPI, retries: int = 10, delay: int = 2) -> None:
    for attempt in range(1, retries + 1):
        try:
            client.get("/")
            return
        except Exception:
            if attempt == retries:
                raise
            time.sleep(delay)


